-- Create "pending_oauth_sessions" table
CREATE TABLE "pending_oauth_sessions" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "session_token_hash" character varying NOT NULL,
  "intent" character varying NOT NULL,
  "provider" character varying NOT NULL,
  "provider_key" character varying NOT NULL,
  "provider_subject_hash" character varying NOT NULL,
  "subject_hint" character varying NOT NULL DEFAULT '',
  "target_user_id" bigint NULL,
  "redirect_to" character varying NOT NULL DEFAULT '/',
  "resolved_email" character varying NOT NULL DEFAULT '',
  "display_name" character varying NOT NULL DEFAULT '',
  "email_verified" boolean NOT NULL DEFAULT false,
  "avatar_url" character varying NOT NULL DEFAULT '',
  "expires_at" timestamptz NOT NULL,
  "consumed_at" timestamptz NULL,
  PRIMARY KEY ("id")
);
-- Create index "pendingoauthsession_session_token_hash" to table: "pending_oauth_sessions"
CREATE UNIQUE INDEX "pendingoauthsession_session_token_hash" ON "pending_oauth_sessions" ("session_token_hash");
-- Create index "pendingoauthsession_target_user_id" to table: "pending_oauth_sessions"
CREATE INDEX "pendingoauthsession_target_user_id" ON "pending_oauth_sessions" ("target_user_id");
-- Create index "pendingoauthsession_expires_at" to table: "pending_oauth_sessions"
CREATE INDEX "pendingoauthsession_expires_at" ON "pending_oauth_sessions" ("expires_at");
-- Create index "pendingoauthsession_consumed_at" to table: "pending_oauth_sessions"
CREATE INDEX "pendingoauthsession_consumed_at" ON "pending_oauth_sessions" ("consumed_at");
-- Create index "pendingoauthsession_provider_provider_key_provider_subject_hash" to table: "pending_oauth_sessions"
CREATE INDEX "pendingoauthsession_provider_provider_key_provider_subject_hash" ON "pending_oauth_sessions" ("provider", "provider_key", "provider_subject_hash");
